var enabled = core.getStelProperty('MeteorShowers.enablePlugin');
core.debug('Plugin enabled: ' + enabled);

// Toggle the plugin on/off
core.setStelProperty('MeteorShowers.enablePlugin', true);

if (MeteorShowers.getEnableLabels()) {
    core.debug("Radiant labels are visible");
} else {
    MeteorShowers.setEnableLabels(true);
}

core.setStelProperty('MeteorShowers.enableLabels', true);
var visible = core.getStelProperty('MeteorShowers.enableLabels');
core.debug("now :" + visible);

if (MeteorShowers.getEnableMarker()) {
    core.debug("Radiant markers are visible");
}

if (MeteorShowers.getActiveRadiantOnly()) {
    core.debug("Only active meteor showers are shown");
}

var color = MeteorShowers.getColorARG();
core.debug("Generic active color: RGB" + color);
// Output example: Generic active color: RGB[0, 1, 0.94]

// Using property system - returns a comma-separated string
var colorStr = core.getStelProperty('MeteorShowers.colorARG');
core.debug("Color as string: " + colorStr);
// Output example: Color as string: 0,1,0.94

var orange = core.vec3f(1.0, 0.5, 0.0);
MeteorShowers.setColorARG(orange);

// Alternative using property system
core.setStelProperty('MeteorShowers.colorARG', orange);

var colorStr = core.getStelProperty('MeteorShowers.colorARG');
core.debug("Color string: " + colorStr);

var newColor = core.vec3f(1.0, 0.5, 0.0);
core.setStelProperty('MeteorShowers.colorARG', newColor);

var color = MeteorShowers.getColorARC();
core.debug("Active confirmed color: RGB" + color);
// Output example: Active confirmed color: RGB[1, 0.941176, 0]

// Using property system - returns a comma-separated string
var colorStr = core.getStelProperty('MeteorShowers.colorARC');
core.debug("Color as string: " + colorStr);
// Output example: Color as string: 1,0.941176,0

var green = core.vec3f(0.2, 0.9, 0.2);
MeteorShowers.setColorARC(green);

// Alternative using property system
core.setStelProperty('MeteorShowers.colorARC', green);

var colorStr = core.getStelProperty('MeteorShowers.colorARC');
var newColor = core.vec3f(0.0, 1.0, 0.0);
core.setStelProperty('MeteorShowers.colorARC', newColor);

var color = MeteorShowers.getColorIR();
core.debug("Inactive color: RGB" + color);
// Output example: Inactive color: RGB[1, 1, 1]

// Using property system - returns a comma-separated string
var colorStr = core.getStelProperty('MeteorShowers.colorIR');
core.debug("Color as string: " + colorStr);
// Output example: Color as string: 1,1,1

var gray = core.vec3f(0.5, 0.5, 0.5);
MeteorShowers.setColorIR(gray);

// Alternative using property system
core.setStelProperty('MeteorShowers.colorIR', gray);

var colorStr = core.getStelProperty('MeteorShowers.colorIR');
var newColor = core.vec3f(0.8, 0.8, 0.8);
core.setStelProperty('MeteorShowers.colorIR', newColor);

if (MeteorShowers.getEnableAtStartup()) {
    core.debug("Meteor showers will appear on next startup");
}

if (MeteorShowers.getShowEnableButton()) {
    core.debug("Enable button is visible on toolbar");
}

if (MeteorShowers.getShowSearchButton()) {
    core.debug("Search button is visible");
}

if (MeteorShowers.getEnableAutoUpdates()) {
    core.debug("Auto updates enabled");
}
